import{_ as a,o as t,c as o,a2 as n}from"./chunks/framework.Bix3-HpO.js";const u=JSON.parse('{"title":"GeoIP","description":"Visitor Country Detection with GeoIP in Nonaki","frontmatter":{"title":"GeoIP","description":"Visitor Country Detection with GeoIP in Nonaki","weight":40,"extra":{"order":40},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/nonaki/geoip"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/nonaki/geoip"}],["meta",{"property":"og:title","content":"GeoIP"}],["meta",{"property":"og:description","content":"Visitor Country Detection with GeoIP in Nonaki"}],["meta",{"name":"twitter:title","content":"GeoIP"}],["meta",{"name":"twitter:description","content":"Visitor Country Detection with GeoIP in Nonaki"}]]},"headers":[],"relativePath":"docs/nonaki/geoip.md","filePath":"docs/nonaki/geoip.md"}'),i={name:"docs/nonaki/geoip.md"};function r(s,e,d,c,l,p){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="geoip" tabindex="-1">GeoIP <a class="header-anchor" href="#geoip" aria-label="Permalink to &quot;GeoIP&quot;">​</a></h1><p>Nonaki can detect the country of your visitors using IP geolocation. When enabled, country data appears in click and impression analytics breakdowns.</p><p>GeoIP is optional. All other features work without it.</p><p>Nonaki uses 2 ways to detect teh visitor&#39;s country: CDN headers or MaxMind GeoLite2.</p><hr><h2 id="cdn-and-proxy-support" tabindex="-1">CDN and Proxy Support <a class="header-anchor" href="#cdn-and-proxy-support" aria-label="Permalink to &quot;CDN and Proxy Support&quot;">​</a></h2><p>If your site is behind Cloudflare or a similar CDN, Nonaki will attempt to read the country from CDN-provided headers (such as <code>CF-IPCountry</code>) before falling back to local GeoIP lookup. This means country detection can work even if you are not using the MaxMind database.</p><hr><h2 id="maxmind-geolite2" tabindex="-1">MaxMind GeoLite2 <a class="header-anchor" href="#maxmind-geolite2" aria-label="Permalink to &quot;MaxMind GeoLite2&quot;">​</a></h2><p>Nonaki uses the free <strong>MaxMind GeoLite2</strong> database for geolocation. You need a free MaxMind account to download it.</p><h3 id="_1-create-a-maxmind-account" tabindex="-1">1. Create a MaxMind Account <a class="header-anchor" href="#_1-create-a-maxmind-account" aria-label="Permalink to &quot;1. Create a MaxMind Account&quot;">​</a></h3><p>Sign up for a free account at <a href="https://www.maxmind.com/en/geolite2/signup" target="_blank" rel="noreferrer">maxmind.com/en/geolite2/signup</a>. No payment is required for GeoLite2.</p><h3 id="_2-generate-a-license-key" tabindex="-1">2. Generate a License Key <a class="header-anchor" href="#_2-generate-a-license-key" aria-label="Permalink to &quot;2. Generate a License Key&quot;">​</a></h3><p>After logging in, go to <strong>Account</strong> → <strong>Manage License Keys</strong> and generate a new key.</p><h3 id="_3-add-the-key-in-nonaki" tabindex="-1">3. Add the Key in Nonaki <a class="header-anchor" href="#_3-add-the-key-in-nonaki" aria-label="Permalink to &quot;3. Add the Key in Nonaki&quot;">​</a></h3><p>Go to <strong>Nonaki Links</strong> → <strong>Settings</strong> → <strong>GeoIP</strong> section. Paste your license key and click <code>Save &amp; Update</code>.</p><p>Nonaki will download the GeoLite2 database files immediately. You should see the database status update to show both <code>GeoLite2-City</code> and <code>GeoLite2-ASN</code> as present.</p><hr><h2 id="auto-update" tabindex="-1">Auto-Update <a class="header-anchor" href="#auto-update" aria-label="Permalink to &quot;Auto-Update&quot;">​</a></h2><p>MaxMind updates the GeoLite2 databases regularly. Enable <strong>Auto-update databases weekly</strong> in the GeoIP settings to keep your data current automatically. When enabled, Nonaki checks for updates once a week via a background cron job.</p><p>You can also trigger an update manually at any time by saving the GeoIP settings.</p><hr><h2 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to &quot;Privacy&quot;">​</a></h2><p>IP addresses are used only to determine the visitor&#39;s country and are not stored in their original form in analytics. See <a href="/docs/nonaki/privacy">Privacy &amp; GDPR</a> for details.</p>',24)])])}const g=a(i,[["render",r]]);export{u as __pageData,g as default};
